generated_oml:
// C3: Physical sensing components
instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Motor current sensor (I_M) measuring electrical current of the permanent‑magnet synchronous motor"
    DTDFVocab:producedData MotorCurrentDataTransmitted
]

instance MotorEncoderSensor : DTDFVocab:SensingComponent [
    base:desc "Motor encoder mounted on the motor providing motor shaft angular position"
    DTDFVocab:producedData MotorEncoderDataTransmitted
]

instance SecondaryEncoderSensor : DTDFVocab:SensingComponent [
    base:desc "Secondary encoder located behind the gearbox providing gearbox output shaft position"
    DTDFVocab:producedData SecondaryEncoderDataTransmitted
]

instance PositionEncoderSensor : DTDFVocab:SensingComponent [
    base:desc "Position encoder delivering output angle of the robot axis"
    DTDFVocab:producedData PositionEncoderDataTransmitted
]

// C4: Physical-to-virtual interaction (DataTransmitted)
instance MotorCurrentDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

instance MotorEncoderDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorEncoderSensor
]

instance SecondaryEncoderDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom SecondaryEncoderSensor
]

instance PositionEncoderDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom PositionEncoderSensor
]

// C10: Data (traces)
instance MotorCurrentData : DTDFVocab:Data [
    base:desc "Raw current trace I_M streamed via MQTT"
    DTDFVocab:fromData MotorCurrentDataTransmitted
    DTDFVocab:inputTo DataStreamingEnabler, SimulinkExecutionEnabler
]

instance TorqueData : DTDFVocab:Data [
    base:desc "Derived torque trace calculated from motor current and encoder data"
    DTDFVocab:fromData MotorCurrentDataTransmitted
    DTDFVocab:inputTo SimulinkExecutionEnabler
]

instance AngularVelocityData : DTDFVocab:Data [
    base:desc "Angular velocity trace derived from position encoder output angle"
    DTDFVocab:fromData PositionEncoderDataTransmitted
    DTDFVocab:inputTo SimulinkExecutionEnabler
]

instance AccelerationData : DTDFVocab:Data [
    base:desc "Angular acceleration derived from successive velocity calculations"
    DTDFVocab:fromData PositionEncoderDataTransmitted
    DTDFVocab:inputTo SimulinkExecutionEnabler
]

// C11: Enablers (tooling)
instance DataStreamingEnabler : DTDFVocab:Enabler [
    base:desc "MQTT broker used for live streaming of sensor traces to the digital shadow"
    DTDFVocab:enables RealTimeVisualizationDashboard
]

instance SimulinkExecutionEnabler : DTDFVocab:Enabler [
    base:desc "MATLAB/Simulink execution environment that runs engineering and friction simulation models"
    DTDFVocab:enables FrictionModelIdentificationService,
                 ParameterEstimationService,
                 MotionControlImprovementService
]

// C6: Services
instance RealTimeVisualizationDashboard : DTDFVocab:Service [
    base:desc "Web‑based real‑time visualization dashboard presenting sensor traces and model outputs"
    DTDFVocab:provides FrictionBehaviorInsight
]

instance FrictionModelIdentificationService : DTDFVocab:Service [
    base:desc "Identification of static, kinetic and viscous friction parameters from streamed data"
    DTDFVocab:provides IdentifiedFrictionParametersInsight
]

instance ParameterEstimationService : DTDFVocab:Service [
    base:desc "Parameter estimation for white‑box and black‑box friction models (Coulomb‑Viscous, Stribeck, Dahl, LuGre)"
    DTDFVocab:provides ParameterEstimationInsight
]

instance MotionControlImprovementService : DTDFVocab:Service [
    base:desc "Support for improving robot motion control accuracy using identified friction parameters"
    DTDFVocab:provides UpdateRobotControllerAction
]

// C17: Insights and Actions
instance FrictionBehaviorInsight : DTDFVocab:Insight [
    base:desc "Operators gain insight into friction behavior and its evolution during operation"
]

instance IdentifiedFrictionParametersInsight : DTDFVocab:Insight [
    base:desc "Friction model parameters identified from data are available for analysis"
]

instance ParameterEstimationInsight : DTDFVocab:Insight [
    base:desc "Estimated parameters for white‑box and black‑box friction models are presented"
]

instance UpdateRobotControllerAction : DTDFVocab:Action [
    base:desc "Identified friction parameters are fed back to the robot controller to improve motion accuracy"
    DTDFVocab:IsAutomatic true
]

// C10: Engineering and Simulation Models
instance SysMLAxisEngineeringModel : DTDFVocab:Model [
    base:desc "SysML block definition and internal block diagrams of the first axis of the MABI MAX 100 robot"
    DTDFVocab:inputTo SimulinkExecutionEnabler
]

instance SimulinkFrictionSimulationModel : DTDFVocab:Model [
    base:desc "MATLAB/Simulink model of motor, gearbox, and friction (Coulomb‑Viscous, Stribeck, Dahl, LuGre)"
    DTDFVocab:inputTo SimulinkExecutionEnabler
]

instance virtual_to_physical_interaction : DTDFVocab:VirtualToPhysical [
    base:desc "None – the digital shadow is a one‑way passive representation and does not send commands or data back to the robot."
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "The digital shadow operates in real‑time during robot operation, processing incoming MQTT data at the sensor sampling rate and updating friction model parameters continuously. This enables near‑instantaneous comparison of measured and simulated torque/velocity traces and supports ongoing model refinement while the robot is running."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "A digital shadow composed of a purpose (friction derivation), the asset (first axis), data traces (measured and simulated), processing components (simulation models), and sources, all instantiated from the Digital Shadow Reference Model and linked through UML class relationships."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "Operated (runtime) stage – the digital shadow continuously identifies friction during robot operation."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Full traceability of each data point to its source and processing model ensures fidelity; analytical friction models are validated against live measurements, and simulation results are compared with reference data to assess model validity."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "Sensor data are transferred to the digital shadow using MQTT; the Asset Administration Shells provide the semantic linking of data and models."
]
